import React, { useState, useEffect } from 'react';
import '../assets/styles/Zoom.css';
import RefreshIcon from '@mui/icons-material/Refresh';
import CloseIcon from '@mui/icons-material/Close';
import axios from 'axios';

const Zoom = () => {
  const [showConfirm, setShowConfirm] = useState(false);
  const [userInfo, setUserInfo] = useState(null);
  const [error, setError] = useState('');
  const [authenticated, setAuthenticated] = useState(null); // Initializăm ca `null` pentru a detecta starea inițială
  const [backendUrl, setBackendUrl] = useState('');

  // Fetch backend URL from the server
  const fetchBackendUrl = async () => {
    try {
      const response = await axios.get('/api/server-info');
      const { ip, port } = response.data;
      const url = `http://${ip}:${port}`;
      setBackendUrl(url);
    } catch (error) {
      console.error('Error fetching backend URL:', error);
    }
  };

  // Check if the user is authenticated
  const checkAuthentication = () => {
    axios.get(`${backendUrl}/shortcuts/zoom/check-auth/`)
      .then(response => {
        const data = response.data;
        if (data.authenticated) {
          setAuthenticated(true);
          fetchUserInfo(); // Fetch user info if authenticated
        } else {
          setAuthenticated(false);
        }
      })
      .catch(err => {
        console.error('Error:', err);
        setAuthenticated(false);
      });
  };

  // Fetch user info from the backend (list of contacts)
  const fetchUserInfo = () => {
    axios.get(`${backendUrl}/shortcuts/zoom/get-contacts/`)
      .then(response => {
        const data = response.data;
        if (data.success) {
          setUserInfo(data.contacts);  // Store user contacts in the state
        } else {
          setError('Unable to fetch user info');
        }
      })
      .catch(err => {
        setError('An error occurred while fetching user info');
        console.error('Error:', err);
      });
  };

  useEffect(() => {
    fetchBackendUrl(); // Fetch the backend URL first
  }, []);

  useEffect(() => {
    if (backendUrl) {
      checkAuthentication(); // Check authentication after backend URL is fetched
    }
  }, [backendUrl]);

  const handleRequest = (url) => {
    axios.post(`${backendUrl}${url}`)
      .catch(error => {
        console.error('Error:', error);
      });
  };

  const handleActivateZoom = () => {
    handleRequest('/shortcuts/zoom/open-zoom/');
  };



  const confirmCloseZoom = () => {
    setShowConfirm(true);
  };

  const handleLogin = () => {
    window.location.href = `${backendUrl}/shortcuts/zoom/oauth/login/`;
  };

  if (authenticated === null) {
    return <p>Verific autentificarea...</p>;
  }

  return (
    <div className="zoom-container">
      <h1 className="title">Zoom</h1>

      {!authenticated ? (
        <button onClick={handleLogin} className="button login-button">
          Autentificare cu Zoom
        </button>
      ) : (
        <>
          {/* Show user contacts */}
          {error && <p className="error">{error}</p>}
          {userInfo && (
            <ul className="user-info-list">
              {userInfo.map((contact, index) => (
                <li key={index}>
                  <strong>Nume:</strong> {contact.first_name} {contact.last_name}<br />
                  <strong>Email:</strong> {contact.email}<br />
                  <strong>Status:</strong> {contact.status}
                </li>
              ))}
            </ul>
          )}

          {/* Zoom Control Buttons */}
          <div className="button-container">
            <button onClick={handleActivateZoom} className="button activate-zoom-button">
              <RefreshIcon className="button-icon" /> Adu în față Zoom
            </button>
            
            
          </div>

          {/* Confirmation Modal */}
          
        </>
      )}
    </div>
  );
};

export default Zoom;
